# How many orders does each restaurant receive?
SELECT RESTAURANT_NAME, COUNT(ORDER_ITEMS_ID) AS TOTAL_ORDERS
FROM RESTAURANT_RECORDS AS RES_R 
RIGHT JOIN ORDERS ON RES_R.RESTAURANT_ID = ORDERS.RESTAURANT_ID
RIGHT JOIN ORDER_ITEMS AS OI ON ORDERS.ORDER_ID = OI.ORDER_ID
GROUP BY RESTAURANT_NAME ;

# Which dish is ordered the most?
SELECT DISH.DISH_NAME, COUNT(OI.DISH_ID) AS ORDERED
FROM DISH 
RIGHT JOIN ORDER_ITEMS AS OI ON DISH.DISH_ID = OI.DISH_ID
GROUP BY DISH.DISH_NAME
ORDER BY COUNT(OI.DISH_ID) DESC
LIMIT 1;

# What is the total revenue generated by each category?
SELECT CATEGORY, ROUND(SUM(PRICE),2) AS TOTAL_REVENUE
FROM CATEGORIES_TABLE AS CT 
RIGHT JOIN ORDER_ITEMS AS OI ON CT.CATEGORY_ID = OI.CATEGORY_ID
GROUP BY CATEGORY
ORDER BY SUM(PRICE) DESC;

# How many orders are placed on each date?
SELECT ORDER_DATE, COUNT(ORDER_ITEMS_ID) AS ORDER_DATE
FROM ORDERS 
RIGHT JOIN ORDER_ITEMS AS OI ON ORDERS.ORDER_ID = OI.ORDER_ID
GROUP BY ORDER_DATE;

# Which are the top 3 restaurants based on revenue?
SELECT RESTAURANT_NAME, ROUND(SUM(PRICE),2) AS REVENUE
FROM RESTAURANT_RECORDS AS RR 
RIGHT JOIN ORDERS ON ORDERS.RESTAURANT_ID = RR.RESTAURANT_ID
RIGHT JOIN ORDER_ITEMS AS OI ON ORDERS.ORDER_ID = OI.ORDER_ID
GROUP BY RESTAURANT_NAME
ORDER BY ROUND(SUM(PRICE),2) DESC
LIMIT 3 ;

# What is the total revenue generated in each city?
SELECT CITY, ROUND(SUM(PRICE),2) AS REVENUE
FROM RESTAURANT_RECORDS AS RR 
RIGHT JOIN LOCATION ON LOCATION.LOCATION_ID = RR.LOCATION_ID
RIGHT JOIN ORDERS ON ORDERS.RESTAURANT_ID = RR.RESTAURANT_ID
RIGHT JOIN ORDER_ITEMS AS OI ON ORDERS.ORDER_ID = OI.ORDER_ID
GROUP BY CITY;

# Which restaurants have not received any orders?
SELECT RESTAURANT_NAME 
FROM RESTAURANT_RECORDS AS RR
LEFT JOIN ORDERS AS O ON RR.RESTAURANT_ID = O.RESTAURANT_ID
WHERE O.ORDER_ID IS NULL ;

# Which restaurant has shown the highest growth in number of orders over time?
SELECT RR.RESTAURANT_NAME, ROUND(SUM(OI.PRICE), 2) AS REVENUE
FROM RESTAURANT_RECORDS AS RR
LEFT JOIN ORDERS AS O ON RR.RESTAURANT_ID = O.RESTAURANT_ID
LEFT JOIN ORDER_ITEMS AS OI ON O.ORDER_ID = OI.ORDER_ID
GROUP BY RR.RESTAURANT_NAME
ORDER BY ROUND(SUM(OI.PRICE), 2) DESC;

# On which dates does the platform receive the highest number of orders?
SELECT ORDER_DATE, COUNT(ORDER_ID) AS TOTAL_ORDERS
FROM ORDERS
GROUP BY ORDER_DATE
ORDER BY TOTAL_ORDERS DESC;

# 👉 Which dishes are frequently ordered together?
SELECT OI1.DISH_ID AS DISH_1, OI2.DISH_ID AS DISH_2, COUNT(*) AS FREQUENCY
FROM ORDER_ITEMS OI1
JOIN ORDER_ITEMS OI2 ON OI1.ORDER_ID = OI2.ORDER_ID AND OI1.DISH_ID < OI2.DISH_ID
GROUP BY OI1.DISH_ID , OI2.DISH_ID
ORDER BY FREQUENCY DESC;

# Which city generates the highest revenue and why?
SELECT CITY, ROUND(SUM(PRICE), 2) AS REVENUE
FROM LOCATION AS LN 
JOIN RESTAURANT_RECORDS AS RR ON LN.LOCATION_ID = RR.LOCATION_ID
JOIN ORDERS AS O ON O.RESTAURANT_ID = RR.RESTAURANT_ID
JOIN ORDER_ITEMS AS OI ON OI.ORDER_ID = O.ORDER_ID
GROUP BY CITY
ORDER BY SUM(PRICE) DESC;

# Which food category contributes the most to total revenue? 
SELECT CATEGORY, ROUND(SUM(PRICE), 2) AS REVENUE
FROM CATEGORIES_TABLE AS CT
JOIN ORDER_ITEMS AS OI ON CT.CATEGORY_ID = OI.CATEGORY_ID
GROUP BY CATEGORY
ORDER BY REVENUE DESC
LIMIT 1;

# What percentage of total revenue comes from top 10 restaurants?
SELECT ROUND( SUM(TOP10_REVENUE) / (SELECT SUM(OI.PRICE) FROM ORDER_ITEMS AS OI) * 100, 2)  AS PERCENTAGE
FROM(SELECT SUM(PRICE) AS TOP10_REVENUE
	FROM RESTAURANT_RECORDS AS RR 
	JOIN ORDERS AS O ON RR.RESTAURANT_ID = O.RESTAURANT_ID 
	JOIN ORDER_ITEMS AS OI ON O.ORDER_ID = OI.ORDER_ID
	GROUP BY RR.RESTAURANT_ID
	ORDER BY TOP10_REVENUE DESC
	LIMIT 10 ) AS T  
;

